import{p as r,bx as i,bh as l,I as d,U as e,A as n,W as t,X as s}from"./chunks/framework.BpabEsSf.js";const _=JSON.parse('{"title":"ローカルストレージと暗号化技術ドキュメント","description":"","frontmatter":{"title":"ローカルストレージと暗号化技術ドキュメント","date":"2026-05-16T13:15:00.000Z","permalink":"/reference/android-storage-security","categories":["Technical Insights"],"tags":["Android","Security","Encryption"]},"headers":[],"relativePath":"ja/02.Configuration/02.Docs/02.Monica Android Local Storage & Encryption Tech Doc.md","filePath":"ja/02.Configuration/02.Docs/02.Monica Android Local Storage & Encryption Tech Doc.md","lastUpdated":null}'),p={name:"ja/02.Configuration/02.Docs/02.Monica Android Local Storage & Encryption Tech Doc.md"};function c(u,a,g,b,h,m){const o=i("Badge");return l(),d("div",null,[a[14]||(a[14]=e('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /ja\\02.Configuration\\02.Docs\\02.Monica Android Local Storage &amp; Encryption Tech Doc.md for this page in Markdown format</div><h1 id="🔒-monica-android-ローカルストレージ-暗号化技術ドキュメント" tabindex="-1">🔒 Monica Android ローカルストレージ＆暗号化技術ドキュメント <a class="header-anchor" href="#🔒-monica-android-ローカルストレージ-暗号化技術ドキュメント" aria-label="Permalink to &quot;🔒 Monica Android ローカルストレージ＆暗号化技術ドキュメント&quot;">​</a></h1><div class="note custom-block"><p class="title note-title custom-block-title">ゼロ知識アーキテクチャ (Zero-Knowledge Architecture)</p><p><code>Monica Android</code> は、ローカルでの永続化および WebDAV バックアップ処理において、ユーザーの機密資産（パスワード、クレジットカード番号、2FA 鍵、セキュアノートなど）の絶対的な安全を確保するため、多層構造のフルディスクおよびフィールド（項目）レベルの階層型暗号化アーキテクチャを採用しています。システムコアは <strong>ゼロ知識アーキテクチャ（Zero-Knowledge）</strong> の原則に厳格に準拠しています。万が一デバイスを紛失したり、データベースファイルが抽出されたりした場合でも、攻撃者がユーザーのマスターパスワードを知らない限り、いかなる明文データも逆向（復元）することは不可能です。</p></div><hr><h2 id="_1-ローカルデータストレージ" tabindex="-1">1. ローカルデータストレージ <a class="header-anchor" href="#_1-ローカルデータストレージ" aria-label="Permalink to &quot;1. ローカルデータストレージ&quot;">​</a></h2><p>Monica は、明文での SQLite ストレージや信頼性の低い Key-Value（KV）構成を排除し、構造化されたデータ管理のために Google が推奨する <strong>Modern Android Development (MAD)</strong> のアーキテクチャ実践を全面的に取り入れています：</p>',6)),n("ul",null,[a[5]||(a[5]=n("li",null,[n("strong",null,"コア永続化層"),t("："),n("code",null,"Room Persistence Library"),t("（SQLite 上の高度な抽象化レイヤー）を介して実装され、高い凝集度を持つデータアクセスオブジェクト（DAO）を維持します。")],-1)),a[6]||(a[6]=n("li",null,[n("strong",null,"物理ファイルの構造"),t("：データは、サンドボックス内に隔離された "),n("code",null,"password_database.db"),t(" ファイルおよび関連する WAL（Write-Ahead Logging）ファイルに直接書き込まれます。")],-1)),n("li",null,[a[0]||(a[0]=n("strong",null,"物理的隔離境界",-1)),a[1]||(a[1]=t()),s(o,{text:"隔離",type:"info"}),a[2]||(a[2]=t("：データは、アプリケーションのプライベートな安全ディレクトリ（",-1)),a[3]||(a[3]=n("code",null,"/data/data/takagi.ru.monica/databases/",-1)),a[4]||(a[4]=t("）内に厳格に封じ込められます。ルート（Root）化されていないデバイスでは、外部の悪意あるプロセスはこのサンドボックス境界を越える権限を持たず、アクセスする手段もありません。",-1))])]),a[15]||(a[15]=e(`<hr><h2 id="_2-コア暗号化アーキテクチャ" tabindex="-1">2. コア暗号化アーキテクチャ <a class="header-anchor" href="#_2-コア暗号化アーキテクチャ" aria-label="Permalink to &quot;2. コア暗号化アーキテクチャ&quot;">​</a></h2><h3 id="_2-1-アルゴリズム選定-aes-256-gcm" tabindex="-1">2.1 アルゴリズム選定：AES-256-GCM <a class="header-anchor" href="#_2-1-アルゴリズム選定-aes-256-gcm" aria-label="Permalink to &quot;2.1 アルゴリズム選定：AES-256-GCM&quot;">​</a></h3><p>Monica のコア暗号化エンジンは、工業級の対称暗号化アルゴリズムである <strong><code>AES-256-GCM</code></strong> (Advanced Encryption Standard with Galois/Counter Mode) を採用しています。</p><div class="tip custom-block"><p class="custom-block-title">なぜ GCM モードを選択するのか？</p><p>CBC などの伝統的なモードは<strong>機密性</strong>しか提供できず、ビット反転（Bit-flipping）攻撃などの改ざんに対して脆弱です。対照的に、<code>GCM</code> は <strong>AEAD (Authenticated Encryption with Associated Data)</strong> モードであり、以下の機能を提供します：</p><ol><li><strong>認証付き暗号</strong>：ペイロードを暗号化すると同時に、16 バイトの認証タグ（Authentication Tag）を生成します。</li><li><strong>完全性検証</strong>：解凍（解読）時にランタイムが自動的にタグを検証します。暗号文または IV への微小な改ざんも即座に検知され、ランタイムのサーキットブレーカーが作動して復号処理を強制遮断（熔断）し、改ざんや中間者（MitM）注入を完全に無効化します。</li></ol></div><h3 id="_2-2-機密データパイプライン-securitymanager" tabindex="-1">2.2 機密データパイプライン (SecurityManager) <a class="header-anchor" href="#_2-2-機密データパイプライン-securitymanager" aria-label="Permalink to &quot;2.2 機密データパイプライン (SecurityManager)&quot;">​</a></h3><p><code>Room</code> データベースの <code>PasswordEntry</code> 表内にある極めて機密性の高いフィールド（パスワード、秘密の質問の答えなど）に対して、Monica は I/O（読み書き）操作中に以下のライフサイクルルーチンをリアルタイムで実行します：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>[明文データ] ➔ 12BのランダムIVを付与 ➔ [AES-256-GCM エンジン] ➔ (IV + 暗号文) として結合 ➔ Base64 エンコード ➔ DBへ書き込み</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ol><li><strong>永続化前の暗号化</strong>：エンジンは <code>SecurityManager</code> を介して生の文字列をインターセプトし、<strong>12 バイトの高エントロピーなランダム IV</strong>（初期化ベクトル）を動的に注入します。</li><li><strong>複合ストレージ構造</strong>：ペイロードは、<code>Base64(IV + CipherText)</code> としてフォーマットされた複合文字列として SQLite のセルに安全に書き込まれます。</li><li><strong>読み込み時の復号</strong>：Room からデータを取得すると、エンジンは自動的に Base64 デコードを実行 ➔ 先頭 12 バイトの IV と後続の暗号文を分離 ➔ ハードウェア鍵と連携して明文を復元します。</li></ol><hr><h2 id="_3-マスターパスワードの派生とハードウェア級の鍵管理" tabindex="-1">3. マスターパスワードの派生とハードウェア級の鍵管理 <a class="header-anchor" href="#_3-マスターパスワードの派生とハードウェア級の鍵管理" aria-label="Permalink to &quot;3. マスターパスワードの派生とハードウェア級の鍵管理&quot;">​</a></h2><h3 id="_3-1-高強度な鍵派生-pbkdf2" tabindex="-1">3.1 高強度な鍵派生 (PBKDF2) <a class="header-anchor" href="#_3-1-高強度な鍵派生-pbkdf2" aria-label="Permalink to &quot;3.1 高強度な鍵派生 (PBKDF2)&quot;">​</a></h3><p>レインボーテーブルの照合やオフラインでの総当たり（ブルートフォース）攻撃を無効化するため、ユーザーのマスターパスワードは<strong>ローカルに永続化されず、そのハッシュ値が保存されることもありません</strong>。代わりに、動的な鍵派生の最高源流（ルートシード）としてのみ機能します：</p>`,13)),n("ul",null,[a[12]||(a[12]=n("li",null,[n("strong",null,"コアプリミティブ"),t("：暗号学標準である "),n("code",null,"PBKDF2WithHmacSHA256"),t(" (Password-Based Key Derivation Function 2) アルゴリズムを利用します。")],-1)),n("li",null,[a[7]||(a[7]=n("strong",null,"反復指標",-1)),a[8]||(a[8]=t()),s(o,{text:"対総当たり攻撃",type:"danger"}),a[9]||(a[9]=t("：高額な ",-1)),a[10]||(a[10]=n("strong",null,[n("code",null,"100,000"),t(" 回の暗号学的ハッシュ反復")],-1)),a[11]||(a[11]=t("が設定されており、攻撃者がオフライン攻撃を行うための計算および時間コストを指数関数的に引き上げます。",-1))]),a[13]||(a[13]=n("li",null,[n("strong",null,"動的ソルト保護"),t("：デバイスの初期化時に、16 バイトの暗号学的ソルト（Salt）がランダムにプロビジョニングされます。これにより、たとえ 2 人のユーザーが全く同じマスターパスワードを使用していても、派生される下位のルートキーは完全に独立したものになります。")],-1))]),a[16]||(a[16]=e(`<h3 id="_3-2-ハードウェア安全区域による防衛-android-keystore" tabindex="-1">3.2 ハードウェア安全区域による防衛 (Android KeyStore) <a class="header-anchor" href="#_3-2-ハードウェア安全区域による防衛-android-keystore" aria-label="Permalink to &quot;3.2 ハードウェア安全区域による防衛 (Android KeyStore)&quot;">​</a></h3><p>派生されたワークキー（作業鍵）や機密性の高いランタイム構成は、Jetpack Security インフラ（<code>EncryptedSharedPreferences</code> および <code>MasterKey</code>）によって強力に保護されています：</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>TEE / SE によるハードウェア隔離</strong> 根本となるマスターキー（Master Key）の生成およびその暗号化演算処理は、完全に隔離されたハードウェア境界内部、すなわち <strong>TEE（高度に隔離された信頼できる実行環境）</strong> または <strong>SE（セキュアエレメント）</strong> チップ内で閉鎖的に実行されます。したがって、たとえ Android OS のランタイムレイヤーが突破されたり、悪意をもってルート（Root）化されたりした場合でも、暗号化鍵を<strong>物理的なハードウェア基盤から剥離・抽出することはできません</strong>。</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>生体認証認可（BiometricPrompt）</strong> ランタイムは、ハードウェアの指紋認証モジュールや 3D 構造光による顔認証とスムーズに連携します。生体認証に成功すると、ハードウェアの安全区域が制限時間付きでワークキーを解放するため、長いマスターパスワードを頻繁に露出させる必要がなく、極上の利便性と厳格な安全性を両立できます。</p></div><hr><h2 id="_4-遠隔バックアップ暗号化仕様-webdav" tabindex="-1">4. 遠隔バックアップ暗号化仕様 (WebDAV) <a class="header-anchor" href="#_4-遠隔バックアップ暗号化仕様-webdav" aria-label="Permalink to &quot;4. 遠隔バックアップ暗号化仕様 (WebDAV)&quot;">​</a></h2><p>自動または手動によるクラウド向けの WebDAV 非同期バックアップタスクがトリガーされると、Monica の <code>AutoBackupWorker</code> は独立した暗号化パイプラインを立ち上げます：</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-nEF5N" id="tab-GOlglYc" checked><label data-title="暗号化パッケージング・パイプライン" for="tab-GOlglYc">暗号化パッケージング・パイプライン</label></div><div class="blocks"><div class="language-text vp-adaptive-theme active line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[サンドボックス内のコア JSON クラスタ] </span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[標準のバイナリ ZIP ストリームへパック] </span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[ユーザーが設定したバックアップパスワードを取得] ➔ [PBKDF2 100k反復による鍵派生]</span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[強固な AES-256-GCM 暗号化を注入] </span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[マジックヘッダー MONICA_ENC_V1 を付加] ➔ 独立した .enc.zip を生成 ➔ WebDAV へアップロード</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div></div></div><ul><li><strong>アンチリプレイと脱関連化（防追跡）</strong>：バックアップが実行されるたびに、高エントロピーなソルト（Salt）と固有の IV が個別に再生成されます。たとえバックアップするデータ内容が連続して全く同一であっても、クラウド上に生成される <code>.enc.zip</code> アーカイブのバイナリ構造は完全に別物になり、クラウドプロバイダーがファイルサイズの物理的特徴などからユーザーのデータをプロファイリング（プライバシー逆向）するのを防ぎます。</li></ul><hr><h2 id="_5-暗号化安全マトリクス概要" tabindex="-1">5. 暗号化安全マトリクス概要 <a class="header-anchor" href="#_5-暗号化安全マトリクス概要" aria-label="Permalink to &quot;5. 暗号化安全マトリクス概要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>セキュリティレイヤー</th><th>採用技術・コンポーネント</th><th>防御対象となる脅威ベクトル</th></tr></thead><tbody><tr><td><strong>ローカルデータの永続化</strong></td><td><code>AES-256-GCM (256-bit)</code></td><td>データベース抽出（ドラッグアウト）攻撃、物理的なビット反転改ざん、サイドチャネル注入</td></tr><tr><td><strong>マスターパスワード保護</strong></td><td><code>PBKDF2 + HMAC-SHA256</code> (100,000回反復)</td><td>オフラインの総当たり（ブルートフォース）攻撃、レインボーテーブル照合、辞書攻撃</td></tr><tr><td><strong>ランタイムキー保護</strong></td><td><code>Android KeyStore (TEE/SE 境界保護)</code></td><td>メモリダンプ（収集）攻撃、ルート権限によるファイル境界の越境窃取、物理チップの剥離・抽出</td></tr><tr><td><strong>クラウドデータストリーム</strong></td><td><code>MONICA_ENC_V1</code> バイナリ流強暗号化</td><td>クラウドインフラ（堅果雲/Nextcloudなど）の侵害、バックアップ通信経路における傍受・盗聴</td></tr></tbody></table>`,12))])}const S=r(p,[["render",c]]);export{_ as __pageData,S as default};
